prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?origId
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" ;
       tai:belongsTo ?corpus .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:originalId ?origId .

  FILTER(
    CONTAINS(LCASE(STR(?modelName)), "admission") ||
    CONTAINS(LCASE(STR(?modelName)), "admissions") ||
    CONTAINS(LCASE(STR(?modelName)), "universit") ||
    CONTAINS(LCASE(STR(?modelName)), "university") ||
    CONTAINS(LCASE(STR(?modelName)), "enroll") ||
    CONTAINS(LCASE(STR(?modelName)), "enrol")
  )
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?origId ?hitLabel
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" ;
       tai:belongsTo ?corpus .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:originalId ?origId .

  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  ?hitElem bbo:name ?hitLabel .
  FILTER(
    CONTAINS(LCASE(STR(?hitLabel)), "admission") ||
    CONTAINS(LCASE(STR(?hitLabel)), "admissions") ||
    CONTAINS(LCASE(STR(?hitLabel)), "universit") ||
    CONTAINS(LCASE(STR(?hitLabel)), "university") ||
    CONTAINS(LCASE(STR(?hitLabel)), "enroll") ||
    CONTAINS(LCASE(STR(?hitLabel)), "enrol")
  )
}
ORDER BY DESC(?created)
LIMIT 25
